class HeaderValidator {
    private static final int MAX_HEADER_KEY_LENGTH = 100;
    private static final int MAX_HEADER_VALUE_LENGTH = 1000;
    private static final int MAX_HEADERS_COUNT = 20;
    
    private static final Pattern VALID_HEADER_KEY_PATTERN = 
        Pattern.compile("^[a-zA-Z0-9_-]+$");
    
    private static final Set<String> ALLOWED_HEADER_KEYS = Set.of(
        "tracking-id",
        "user-id",
        "session-id",
        "request-id",
        "client-version",
        "platform",
        "event-type",
        "timestamp",
        "correlation-id",
        "source-system"
    );
    
    private static final Set<String> SENSITIVE_PATTERNS = Set.of(
        "password",
        "secret",
        "token",
        "api-key",
        "apikey",
        "auth",
        "credential",
        "private",
        "ssn",
        "credit-card"
    );

    public ValidationResult validate(Map<String, String> headers) {
        if (headers == null) {
            return ValidationResult.success(Collections.emptyMap());
        }

        if (headers.size() > MAX_HEADERS_COUNT) {
            return ValidationResult.error("Too many headers. Maximum allowed: " + MAX_HEADERS_COUNT);
        }

        Map<String, String> validatedHeaders = new HashMap<>();

        for (Map.Entry<String, String> entry : headers.entrySet()) {
            String key = entry.getKey();
            String value = entry.getValue();

            if (key == null || key.trim().isEmpty()) {
                return ValidationResult.error("Header key cannot be null or empty");
            }

            if (value == null) {
                return ValidationResult.error("Header value cannot be null for key: " + key);
            }

            key = key.trim().toLowerCase();

            if (key.length() > MAX_HEADER_KEY_LENGTH) {
                return ValidationResult.error("Header key too long: " + key);
            }

            if (value.length() > MAX_HEADER_VALUE_LENGTH) {
                return ValidationResult.error("Header value too long for key: " + key);
            }

            if (!VALID_HEADER_KEY_PATTERN.matcher(key).matches()) {
                return ValidationResult.error("Invalid header key format: " + key);
            }

            if (!ALLOWED_HEADER_KEYS.contains(key)) {
                return ValidationResult.error("Header key not in allowlist: " + key);
            }

            for (String sensitivePattern : SENSITIVE_PATTERNS) {
                if (key.contains(sensitivePattern) || value.toLowerCase().contains(sensitivePattern)) {
                    return ValidationResult.error("Potentially sensitive data detected in headers");
                }
            }

            String sanitizedValue = sanitizeValue(value);
            validatedHeaders.put(key, sanitizedValue);
        }

        return ValidationResult.success(validatedHeaders);
    }

    private String sanitizeValue(String value) {
        return value.trim()
                   .replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]", "")
                   .replaceAll("\\s+", " ");
    }
}

class ValidationResult {
    private final boolean valid;
    private final String errorMessage;
    private final Map<String, String> validatedHeaders;

    private ValidationResult(boolean valid, String errorMessage, Map<String, String> validatedHeaders) {
        this.valid = valid;
        this.errorMessage = errorMessage;
        this.validatedHeaders = validatedHeaders;
    }

    public static ValidationResult success(Map<String, String> headers) {
        return new ValidationResult(true, null, headers);
    }

    public static ValidationResult error(String message) {
        return new ValidationResult(false, message, null);
    }

    public boolean isValid() {
        return valid;
    }

    public String getErrorMessage() {
        return errorMessage;
    }

    public Map<String, String> getValidatedHeaders() {
        return validatedHeaders;
    }
}

