@RestController
@RequestMapping("/api/events")
class EventProducerController {
    
    private static final Pattern VALID_TOPIC_PATTERN = Pattern.compile("^[a-zA-Z0-9._-]+$");
    private static final int MAX_TOPIC_LENGTH = 249;
    private static final int MAX_PAYLOAD_SIZE = 1048576;
    private static final Set<String> ALLOWED_TOPICS = Set.of(
        "user-events",
        "system-events",
        "tracking-events",
        "analytics-events"
    );

    @Autowired
    private Producer<String, String> kafkaProducer;

    private final HeaderValidator headerValidator = new HeaderValidator();

    @PostMapping("/publish")
    public ResponseEntity<ProducerResponse> publishEvent(@RequestBody EventMessage eventMessage) {
        try {
            ValidationResult topicValidation = validateTopic(eventMessage.getTopic());
            if (!topicValidation.isValid()) {
                return ResponseEntity.badRequest()
                    .body(new ProducerResponse(false, topicValidation.getErrorMessage()));
            }

            ValidationResult payloadValidation = validatePayload(eventMessage.getPayload());
            if (!payloadValidation.isValid()) {
                return ResponseEntity.badRequest()
                    .body(new ProducerResponse(false, payloadValidation.getErrorMessage()));
            }

            ValidationResult headerValidation = headerValidator.validate(eventMessage.getHeaders());
            if (!headerValidation.isValid()) {
                return ResponseEntity.badRequest()
                    .body(new ProducerResponse(false, headerValidation.getErrorMessage()));
            }

            List<Header> kafkaHeaders = new ArrayList<>();
            for (Map.Entry<String, String> entry : headerValidation.getValidatedHeaders().entrySet()) {
                kafkaHeaders.add(new RecordHeader(
                    entry.getKey(), 
                    entry.getValue().getBytes(StandardCharsets.UTF_8)
                ));
            }

            String key = eventMessage.getKey() != null ? 
                sanitizeKey(eventMessage.getKey()) : UUID.randomUUID().toString();

            ProducerRecord<String, String> record = new ProducerRecord<>(
                eventMessage.getTopic(),
                null,
                key,
                eventMessage.getPayload(),
                kafkaHeaders
            );

            Future<RecordMetadata> future = kafkaProducer.send(record);
            RecordMetadata metadata = future.get();

            return ResponseEntity.ok(new ProducerResponse(
                true,
                "Event published successfully",
                metadata.topic(),
                metadata.partition(),
                metadata.offset()
            ));

        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(new ProducerResponse(false, "Failed to publish event"));
        }
    }

    private ValidationResult validateTopic(String topic) {
        if (topic == null || topic.trim().isEmpty()) {
            return ValidationResult.error("Topic cannot be null or empty");
        }

        topic = topic.trim();

        if (topic.length() > MAX_TOPIC_LENGTH) {
            return ValidationResult.error("Topic name too long");
        }

        if (!VALID_TOPIC_PATTERN.matcher(topic).matches()) {
            return ValidationResult.error("Invalid topic name format");
        }

        if (!ALLOWED_TOPICS.contains(topic)) {
            return ValidationResult.error("Topic not in allowlist");
        }

        return ValidationResult.success(null);
    }

    private ValidationResult validatePayload(String payload) {
        if (payload == null || payload.trim().isEmpty()) {
            return ValidationResult.error("Payload cannot be null or empty");
        }

        if (payload.getBytes(StandardCharsets.UTF_8).length > MAX_PAYLOAD_SIZE) {
            return ValidationResult.error("Payload size exceeds maximum allowed");
        }

        return ValidationResult.success(null);
    }

    private String sanitizeKey(String key) {
        if (key == null || key.trim().isEmpty()) {
            return UUID.randomUUID().toString();
        }
        return key.trim().substring(0, Math.min(key.length(), 200));
    }
}